class Solution:
    def countArrays(self, digitSum):
        MOD = 1000000007
        MAXV = 5000
        def dsum(v):
            s = 0
            while v > 0:
                s += v % 10
                v //= 10
            return s
        ds = [dsum(v) for v in range(MAXV + 1)]
        lists = [[v for v in range(MAXV + 1) if ds[v] == d] for d in digitSum]
        if any(len(l) == 0 for l in lists):
            return 0
        prev_counts = {v: 1 for v in lists[0]}
        for i in range(1, len(lists)):
            cur = {}
            for v in lists[i]:
                total = 0
                for u, c in prev_counts.items():
                    if u <= v:
                        total += c
                if total:
                    cur[v] = total % MOD
            prev_counts = cur
        return sum(prev_counts.values()) % MOD

