class Solution:
    def countArrays(self, digitSum):
        MOD = 1000000007
        MAXV = 5000
        def dsum(v):
            s = 0
            while v > 0:
                s += v % 10
                v //= 10
            return s
        ds = [dsum(v) for v in range(MAXV + 1)]
        buckets = {}
        for v in range(MAXV + 1):
            buckets.setdefault(ds[v], []).append(v)
        n = len(digitSum)
        first = buckets.get(digitSum[0], [])
        if not first:
            return 0
        dp = [0] * (MAXV + 1)
        for v in first:
            dp[v] = 1
        for i in range(1, n):
            cum = 0
            prefix = [0] * (MAXV + 1)
            for v in range(MAXV + 1):
                cum = (cum + dp[v]) % MOD
                prefix[v] = cum
            target_list = buckets.get(digitSum[i], [])
            if not target_list:
                return 0
            newdp = [0] * (MAXV + 1)
            for v in target_list:
                newdp[v] = prefix[v]
            dp = newdp
        return sum(dp) % MOD

