var countArrays = function(digitSum) {
    const MOD = 1000000007;
    const MAXV = 5000;
    function dsum(v) {
        let s = 0;
        while (v > 0) { s += v % 10; v = Math.floor(v / 10); }
        return s;
    }
    const ds = new Array(MAXV + 1);
    for (let v = 0; v <= MAXV; v++) ds[v] = dsum(v);
    const buckets = new Map();
    for (let v = 0; v <= MAXV; v++) {
        if (!buckets.has(ds[v])) buckets.set(ds[v], []);
        buckets.get(ds[v]).push(v);
    }
    const n = digitSum.length;
    const first = buckets.get(digitSum[0]) || [];
    if (first.length === 0) return 0;
    let dp = new Array(MAXV + 1).fill(0);
    for (const v of first) dp[v] = 1;
    for (let i = 1; i < n; i++) {
        let cum = 0;
        const prefix = new Array(MAXV + 1);
        for (let v = 0; v <= MAXV; v++) {
            cum = (cum + dp[v]) % MOD;
            prefix[v] = cum;
        }
        const targetList = buckets.get(digitSum[i]) || [];
        if (targetList.length === 0) return 0;
        const newdp = new Array(MAXV + 1).fill(0);
        for (const v of targetList) newdp[v] = prefix[v];
        dp = newdp;
    }
    let total = 0;
    for (let v = 0; v <= MAXV; v++) total = (total + dp[v]) % MOD;
    return total;
};
